from dataclasses import dataclass

@dataclass
class QualityReport:
    ticket_id: str
    customer_id: str
    sample_prompt: str
    sample_response: str
    expected_response_description: str
    model_version: str | None
    api_params: dict   # temperature, max_tokens, top_p, etc.

def triage_quality_report(report: QualityReport) -> dict:
    signals = {}

    # Check for known prompt design issues
    if len(report.sample_prompt) < 50:
        signals["short_prompt"] = "Prompt may be under-specified; ask customer for full context"

    if report.api_params.get("temperature", 1.0) > 1.2:
        signals["high_temperature"] = "Temperature > 1.2 increases output variance; likely prompt design"

    max_tokens = report.api_params.get("max_tokens", None)
    if max_tokens and max_tokens < 100:
        signals["low_max_tokens"] = "max_tokens may be truncating the response"

    if not report.model_version:
        signals["no_model_pin"] = (
            "Customer is not pinning model version — may be affected by a model update; "
            "check whether the issue started after a known model rollout date"
        )

    escalate_to_l3 = (
        not signals   # no prompt design signals found
        and len(report.sample_prompt) > 100  # non-trivial prompt
    )

    return {
        "signals": signals,
        "recommendation": "escalate_to_l3" if escalate_to_l3 else "resolve_at_l2",
        "escalation_reason": "No prompt design issues identified — possible model regression" if escalate_to_l3 else None,
    }

from dataclasses import dataclass
from datetime import datetime

@dataclass
class EscalationRequest:
    ticket_id: str
    from_tier: SupportTier
    to_tier: SupportTier
    reason: str
    reproduction_steps: str | None   # required for L2→L3 for model bugs
    escalated_at: datetime
    escalated_by: str

    def validate(self) -> list[str]:
        errors = []
        if self.from_tier == SupportTier.L2 and self.to_tier == SupportTier.L3:
            # Model bug escalations require a reproduction
            if ("model" in self.reason.lower() or "bug" in self.reason.lower()):
                if not self.reproduction_steps:
                    errors.append(
                        "L2→L3 escalations for model issues require reproduction_steps. "
                        "Produce a minimal reproduction before escalating."
                    )
        if not self.reason.strip():
            errors.append("escalation reason must be non-empty")
        return errors

from datetime import datetime, timedelta
from dataclasses import dataclass
from enum import Enum

class BreachStatus(str, Enum):
    OK          = "ok"
    WARNING     = "warning"   # > 80% of SLA elapsed, no response
    BREACHED    = "breached"  # > 100% of SLA elapsed, no response

@dataclass
class SLAMonitor:
    ticket_id: str
    tier: str                   # "L1", "L2", "L3"
    opened_at: datetime
    first_response_at: datetime | None
    is_enterprise: bool

    FIRST_RESPONSE_SLA_HOURS = {"L1": 4.0, "L2": 2.0, "L3": 1.0}

    def elapsed_hours(self, as_of: datetime | None = None) -> float:
        ref = as_of or datetime.utcnow()
        return (ref - self.opened_at).total_seconds() / 3600

    def status(self, as_of: datetime | None = None) -> BreachStatus:
        if self.first_response_at is not None:
            return BreachStatus.OK
        sla = self.FIRST_RESPONSE_SLA_HOURS[self.tier]
        elapsed = self.elapsed_hours(as_of)
        if elapsed >= sla:
            return BreachStatus.BREACHED
        if elapsed >= 0.8 * sla:
            return BreachStatus.WARNING
        return BreachStatus.OK

    def alert_targets(self) -> list[str]:
        targets = ["#support-alerts"]
        if self.status() == BreachStatus.BREACHED:
            targets.append("#support-management")
        if self.is_enterprise and self.status() != BreachStatus.OK:
            targets.append("#enterprise-success")
        return targets

from dataclasses import dataclass
import re

SAFETY_SIGNAL_PATTERNS = [
    r"(?i)(harmful|unsafe|violat|policy|restricted|blocked)",
    r"(?i)(system prompt|jailbreak|bypass|ignore instructions)",
    r"(?i)(content filter|moderation|refused)",
]

DATA_EXPOSURE_PATTERNS = [
    r"(?i)(data leak|exposed|another user|someone else.{0,20}(data|message|history))",
    r"(?i)(personal information|pii|private (data|conversation))",
    r"(?i)(account (data|content|history) visible)",
]

@dataclass
class TicketClassifier:
    ticket_body: str
    customer_supplied_category: str

    def inferred_tier(self) -> str:
        body = self.ticket_body
        for pattern in DATA_EXPOSURE_PATTERNS:
            if re.search(pattern, body):
                return "L3"    # data exposure always L3
        for pattern in SAFETY_SIGNAL_PATTERNS:
            if re.search(pattern, body):
                return "L3"    # safety violations always L3
        if re.search(r"(?i)(reproducible|regression|always fails|every request)", body):
            return "L2"        # systematic bugs suggest L2
        return "L1"            # default: assume documentation/usage question

    def classification_conflict(self) -> bool:
        # Returns True when inferred tier is higher than supplied category suggests
        supplied_is_l1 = "billing" in self.customer_supplied_category.lower() \
                         or "account" in self.customer_supplied_category.lower()
        return supplied_is_l1 and self.inferred_tier() in ("L2", "L3")
